(()=>{const e=document.getElementById("menu-toggle"),t=document.getElementById("menu");e&&t&&e.addEventListener("click",()=>{const n="true"===e.getAttribute("aria-expanded");e.setAttribute("aria-expanded",String(!n)),t.classList.toggle("open")});const n=document.getElementById("heroNodes");if(n)for(let e=0;e<20;e++){const e=document.createElement("div");e.className="node",e.style.left=100*Math.random()+"%",e.style.animationDuration=8+12*Math.random()+"s",e.style.animationDelay=10*Math.random()+"s";const t=3+5*Math.random();e.style.width=`${t}px`,e.style.height=`${t}px`,n.appendChild(e)}"serviceWorker"in navigator&&window.addEventListener("load",()=>{navigator.serviceWorker.register("/service-worker.js").catch(()=>{})})})();